const item = $input.item.json;

const primaryName = item.primary_subject_name || "";
const fullName = item.full_name || "";
const companyName = item.company_name || "";
const dob = item.date_of_birth || "";
const nationality = item.nationality || "";
const residence = item.country_of_residence || "";
const aliases = Array.isArray(item.aliases) ? item.aliases.filter(Boolean) : [];
const subjectType = item.subject_type || "";

const g20Countries = [
  "Argentina",
  "Australia",
  "Brazil",
  "Canada",
  "China",
  "France",
  "Germany",
  "India",
  "Indonesia",
  "Italy",
  "Japan",
  "Mexico",
  "Russia",
  "Saudi Arabia",
  "South Africa",
  "South Korea",
  "Turkey",
  "United Kingdom",
  "United States",
  "European Union"
];

const politicalTitles = [
  "president",
  "prime minister",
  "minister",
  "deputy minister",
  "member of parliament",
  "mp",
  "senator",
  "governor",
  "mayor",
  "cabinet",
  "public official",
  "government official",
  "politician",
  "political party",
  "ambassador",
  "judge",
  "chairperson",
  "state secretary",
  "royal family",
  "head of state"
];

const sanctionsTerms = [
  "sanctions",
  "OFAC",
  "SDN",
  "EU sanctions",
  "UN sanctions",
  "HM Treasury sanctions",
  "watchlist",
  "blacklist",
  "asset freeze",
  "restricted party"
];

const offshoreTerms = [
  "offshore",
  "beneficial owner",
  "UBO",
  "shell company",
  "Panama Papers",
  "Paradise Papers",
  "Pandora Papers",
  "leaked records",
  "tax haven",
  "nominee director"
];

const adverseTerms = [
  "fraud",
  "scam",
  "money laundering",
  "bribery",
  "corruption",
  "embezzlement",
  "forgery",
  "kickback",
  "terror financing",
  "criminal case",
  "investigation",
  "raided",
  "charged",
  "arrested",
  "convicted",
  "lawsuit",
  "regulatory action",
  "enforcement action",
  "misconduct",
  "ponzi",
  "cheating"
];

const corporateTerms = [
  "director",
  "shareholder",
  "beneficial owner",
  "board member",
  "company",
  "ownership",
  "subsidiary",
  "affiliate",
  "corporate filings",
  "registry",
  "incorporated",
  "secretary"
];

const identityTerms = [
  "biography",
  "profile",
  "cv",
  "linkedin",
  "company profile",
  "official website"
];

const relationTerms = [
  "associate",
  "linked to",
  "close associate",
  "family member",
  "relative",
  "spouse",
  "advisor",
  "donor",
  "political connection",
  "connected to minister",
  "connected to government"
];

const baseNames = [primaryName, fullName, companyName, ...aliases]
  .map(v => (v || "").trim())
  .filter((v, i, arr) => v && arr.indexOf(v) === i);

const countryPriority = [nationality, residence]
  .map(v => (v || "").trim())
  .filter((v, i, arr) => v && arr.indexOf(v) === i);

const jurisdictionSet = new Set(countryPriority);

if (item.geography_scope?.g20_expand) {
  for (const country of g20Countries) {
    jurisdictionSet.add(country);
  }
}

const jurisdictions = Array.from(jurisdictionSet);

const searchBuckets = {
  identity_resolution: [],
  pep_public_office: [],
  political_links: [],
  sanctions_watchlists: [],
  offshore_financial_integrity: [],
  adverse_media: [],
  scam_fraud_misconduct: [],
  corporate_links_ownership: []
};

function addUnique(bucket, value) {
  if (!value) return;
  if (!searchBuckets[bucket].includes(value)) {
    searchBuckets[bucket].push(value);
  }
}

for (const name of baseNames) {
  addUnique("identity_resolution", `"${name}"`);
  for (const term of identityTerms) {
    addUnique("identity_resolution", `"${name}" ${term}`);
  }
  if (dob) addUnique("identity_resolution", `"${name}" "${dob}"`);
  if (nationality) addUnique("identity_resolution", `"${name}" "${nationality}"`);
  if (residence) addUnique("identity_resolution", `"${name}" "${residence}"`);

  for (const country of countryPriority) {
    addUnique("identity_resolution", `"${name}" "${country}"`);
    if (dob) addUnique("identity_resolution", `"${name}" "${country}" "${dob}"`);
  }

  for (const title of politicalTitles) {
    addUnique("pep_public_office", `"${name}" ${title}`);
  }

  addUnique("pep_public_office", `"${name}" PEP`);
  addUnique("pep_public_office", `"${name}" politically exposed person`);
  addUnique("pep_public_office", `"${name}" public office`);

  for (const country of jurisdictions) {
    addUnique("pep_public_office", `"${name}" "${country}" PEP`);
    addUnique("pep_public_office", `"${name}" "${country}" politician`);
    addUnique("pep_public_office", `"${name}" "${country}" minister`);
    addUnique("pep_public_office", `"${name}" "${country}" member of parliament`);
    addUnique("pep_public_office", `"${name}" "${country}" government official`);
  }

  for (const relation of relationTerms) {
    addUnique("political_links", `"${name}" ${relation}`);
  }

  for (const country of jurisdictions) {
    addUnique("political_links", `"${name}" "${country}" political connection`);
    addUnique("political_links", `"${name}" "${country}" government connection`);
    addUnique("political_links", `"${name}" "${country}" linked to politician`);
    addUnique("political_links", `"${name}" "${country}" linked to minister`);
    addUnique("political_links", `"${name}" "${country}" politically connected`);
  }

  for (const term of sanctionsTerms) {
    addUnique("sanctions_watchlists", `"${name}" ${term}`);
  }

  for (const country of jurisdictions) {
    addUnique("sanctions_watchlists", `"${name}" "${country}" sanctions`);
    addUnique("sanctions_watchlists", `"${name}" "${country}" watchlist`);
  }

  for (const term of offshoreTerms) {
    addUnique("offshore_financial_integrity", `"${name}" ${term}`);
  }

  for (const term of adverseTerms) {
    addUnique("adverse_media", `"${name}" ${term}`);
    addUnique("scam_fraud_misconduct", `"${name}" ${term}`);
  }

  for (const country of jurisdictions) {
    addUnique("adverse_media", `"${name}" "${country}" fraud`);
    addUnique("adverse_media", `"${name}" "${country}" corruption`);
    addUnique("adverse_media", `"${name}" "${country}" investigation`);
    addUnique("scam_fraud_misconduct", `"${name}" "${country}" scam`);
    addUnique("scam_fraud_misconduct", `"${name}" "${country}" cheating`);
    addUnique("scam_fraud_misconduct", `"${name}" "${country}" enforcement action`);
  }

  for (const term of corporateTerms) {
    addUnique("corporate_links_ownership", `"${name}" ${term}`);
  }

  for (const country of jurisdictions) {
    addUnique("corporate_links_ownership", `"${name}" "${country}" director`);
    addUnique("corporate_links_ownership", `"${name}" "${country}" shareholder`);
    addUnique("corporate_links_ownership", `"${name}" "${country}" beneficial owner`);
    addUnique("corporate_links_ownership", `"${name}" "${country}" company registry`);
  }
}

if (subjectType === "organization" || companyName) {
  const orgNames = [companyName, primaryName].map(v => (v || "").trim()).filter((v, i, arr) => v && arr.indexOf(v) === i);

  for (const org of orgNames) {
    addUnique("identity_resolution", `"${org}" official website`);
    addUnique("identity_resolution", `"${org}" company profile`);

    addUnique("pep_public_office", `"${org}" state owned`);
    addUnique("pep_public_office", `"${org}" government owned`);
    addUnique("pep_public_office", `"${org}" politically exposed`);

    addUnique("political_links", `"${org}" political links`);
    addUnique("political_links", `"${org}" government links`);
    addUnique("political_links", `"${org}" linked to politician`);

    for (const term of sanctionsTerms) {
      addUnique("sanctions_watchlists", `"${org}" ${term}`);
    }

    for (const term of offshoreTerms) {
      addUnique("offshore_financial_integrity", `"${org}" ${term}`);
    }

    for (const term of adverseTerms) {
      addUnique("adverse_media", `"${org}" ${term}`);
      addUnique("scam_fraud_misconduct", `"${org}" ${term}`);
    }

    for (const term of corporateTerms) {
      addUnique("corporate_links_ownership", `"${org}" ${term}`);
    }

    for (const country of jurisdictions) {
      addUnique("political_links", `"${org}" "${country}" government connection`);
      addUnique("sanctions_watchlists", `"${org}" "${country}" sanctions`);
      addUnique("scam_fraud_misconduct", `"${org}" "${country}" scam`);
      addUnique("scam_fraud_misconduct", `"${org}" "${country}" fraud`);
      addUnique("corporate_links_ownership", `"${org}" "${country}" registry`);
      addUnique("corporate_links_ownership", `"${org}" "${country}" beneficial owner`);
    }
  }
}

const reviewFocus = {
  identify_possible_pep: true,
  identify_political_connections: true,
  identify_sanctions_or_watchlist_hits: true,
  identify_offshore_or_ubo_links: true,
  identify_adverse_media: true,
  identify_scam_fraud_or_misconduct: true,
  identify_corporate_and_ownership_links: true,
  human_decision_required: true
};

const searchStrategyHints = [
  "Prioritize nationality and residence countries before broad G20 expansion.",
  "Treat exact-name matches with DOB or country overlap as stronger identity candidates.",
  "Separate confirmed matches from possible matches and false positives.",
  "Do not conclude the subject is a PEP unless the finding clearly ties the name to a public role or close political connection.",
  "Flag scam, fraud, corruption, enforcement, and criminal allegations separately from confirmed legal outcomes.",
  "For organizations, check whether beneficial owners, directors, or controlling persons are politically exposed or adverse."
];

return [
  {
    json: {
      ...item,
      search_input: {
        base_names: baseNames,
        priority_countries: countryPriority,
        jurisdictions,
        search_buckets: searchBuckets,
        review_focus: reviewFocus,
        search_strategy_hints: searchStrategyHints
      },
      processing_status: "search_inputs_built"
    }
  }
];

const aiItem = $input.item.json;

// Pull original context from the node before the AI agent
const sourceItem = $("PLANNING | Build Search Inputs").item.json || {};

const raw =
  aiItem.output ||
  aiItem.text ||
  aiItem.response ||
  aiItem.result ||
  aiItem.message ||
  "";

let parsedPlan = null;
let parseError = null;

try {
  parsedPlan = typeof raw === "string" ? JSON.parse(raw) : raw;
} catch (err) {
  parseError = err.message;
}

return [
  {
    json: {
      case_id: sourceItem.case_id || "",
      subject_type: sourceItem.subject_type || "",
      primary_subject_name: sourceItem.primary_subject_name || "",
      full_name: sourceItem.full_name || "",
      company_name: sourceItem.company_name || "",
      date_of_birth: sourceItem.date_of_birth || "",
      nationality: sourceItem.nationality || "",
      country_of_residence: sourceItem.country_of_residence || "",
      aliases: sourceItem.aliases || [],
      geography_scope: sourceItem.geography_scope || {},
      workflow_control: sourceItem.workflow_control || {},
      screening_categories: sourceItem.screening_categories || [],
      notes: sourceItem.notes || "",
      search_input: sourceItem.search_input || {},
      ai_search_plan_raw: raw,
      ai_search_plan: parsedPlan,
      ai_search_plan_parse_error: parseError,
      processing_status: parsedPlan ? "search_plan_ready" : "search_plan_parse_failed"
    }
  }
];

const item = $input.item.json;

const plan = item.ai_search_plan || {};
const categoryPlan = plan.category_plan || {};
const identityPriority = plan.identity_priority || {};

const prioritySequence = Array.isArray(plan.priority_sequence)
  ? plan.priority_sequence
  : [
      "identity_resolution",
      "pep_public_office",
      "political_links",
      "sanctions_watchlists",
      "offshore_financial_integrity",
      "adverse_media",
      "scam_fraud_misconduct",
      "corporate_links_ownership"
    ];

const executionQueue = [];
let rank = 1;

function pushQuery(category, query, priorityBand) {
  if (!query || typeof query !== "string") return;

  executionQueue.push({
    queue_rank: rank++,
    category,
    query,
    priority_band: priorityBand,
    subject_name: item.primary_subject_name || "",
    case_id: item.case_id || "",
    subject_type: item.subject_type || "",
    source_type: "web_search",
    execution_status: "pending"
  });
}

const identityQueries = Array.isArray(identityPriority.identity_queries)
  ? identityPriority.identity_queries
  : [];

for (const query of identityQueries) {
  pushQuery("identity_resolution", query, "high");
}

for (const category of prioritySequence) {
  const queries = Array.isArray(categoryPlan[category]) ? categoryPlan[category] : [];

  for (const query of queries) {
    const priorityBand =
      category === "pep_public_office" || category === "sanctions_watchlists"
        ? "high"
        : category === "corporate_links_ownership" || category === "adverse_media"
        ? "medium"
        : "medium";

    pushQuery(category, query, priorityBand);
  }
}

const deduped = [];
const seen = new Set();

for (const row of executionQueue) {
  const key = `${row.category}||${row.query}`.toLowerCase();
  if (!seen.has(key)) {
    seen.add(key);
    deduped.push(row);
  }
}

return [
  {
    json: {
      ...item,
      search_execution_queue: deduped,
      search_execution_queue_count: deduped.length,
      processing_status: "search_execution_queue_ready"
    }
  }
];

const item = $input.item.json;
const queue = Array.isArray(item.search_execution_queue)
  ? item.search_execution_queue
  : [];

return queue.map((q) => {
  return {
    json: {
      case_id: item.case_id,
      subject_type: item.subject_type,
      primary_subject_name: item.primary_subject_name,
      full_name: item.full_name,
      company_name: item.company_name,
      date_of_birth: item.date_of_birth,
      nationality: item.nationality,
      country_of_residence: item.country_of_residence,
      aliases: item.aliases || [],
      geography_scope: item.geography_scope || {},
      workflow_control: item.workflow_control || {},
      search_task: q,
      processing_status: "search_task_ready"
    }
  };
});

const response = $input.item.json;

// Pull the matching pre-request item from the queue-expansion node
const sourceItem = $("SEARCH | Expand Queue Items").item.json || {};

const searchTask = sourceItem.search_task || {};
const caseId = sourceItem.case_id || "";
const subjectName = sourceItem.primary_subject_name || "";

// Serper result blocks
const organic = Array.isArray(response.organic) ? response.organic : [];
const knowledgeGraph = response.knowledgeGraph || null;
const answerBox = response.answerBox || null;

const findings = [];

for (const row of organic) {
  findings.push({
    finding_type: "organic_result",
    case_id: caseId,
    subject_name: subjectName,
    category: searchTask.category || "",
    query: searchTask.query || "",
    title: row.title || "",
    link: row.link || "",
    snippet: row.snippet || "",
    source: (() => {
      try {
        return row.link ? new URL(row.link).hostname : "";
      } catch {
        return "";
      }
    })(),
    queue_rank: searchTask.queue_rank || null,
    priority_band: searchTask.priority_band || "",
    extraction_confidence: "raw_search_result"
  });
}

if (knowledgeGraph) {
  findings.push({
    finding_type: "knowledge_graph",
    case_id: caseId,
    subject_name: subjectName,
    category: searchTask.category || "",
    query: searchTask.query || "",
    title: knowledgeGraph.title || "",
    link: knowledgeGraph.website || "",
    snippet: knowledgeGraph.description || "",
    source: "knowledge_graph",
    queue_rank: searchTask.queue_rank || null,
    priority_band: searchTask.priority_band || "",
    extraction_confidence: "raw_search_result"
  });
}

if (answerBox) {
  findings.push({
    finding_type: "answer_box",
    case_id: caseId,
    subject_name: subjectName,
    category: searchTask.category || "",
    query: searchTask.query || "",
    title: answerBox.title || "",
    link: answerBox.link || "",
    snippet: answerBox.answer || answerBox.snippet || answerBox.title || "",
    source: "answer_box",
    queue_rank: searchTask.queue_rank || null,
    priority_band: searchTask.priority_band || "",
    extraction_confidence: "raw_search_result"
  });
}

const basePayload = {
  case_id: sourceItem.case_id || "",
  subject_type: sourceItem.subject_type || "",
  primary_subject_name: sourceItem.primary_subject_name || "",
  full_name: sourceItem.full_name || "",
  company_name: sourceItem.company_name || "",
  date_of_birth: sourceItem.date_of_birth || "",
  nationality: sourceItem.nationality || "",
  country_of_residence: sourceItem.country_of_residence || "",
  aliases: sourceItem.aliases || [],
  geography_scope: sourceItem.geography_scope || {},
  workflow_control: sourceItem.workflow_control || {},
  ai_search_plan: sourceItem.ai_search_plan || {}
};

return findings.length
  ? findings.map((f) => ({
      json: {
        ...basePayload,
        normalized_finding: f,
        processing_status: "finding_normalized"
      }
    }))
  : [
      {
        json: {
          ...basePayload,
          normalized_finding: {
            finding_type: "no_results",
            case_id: caseId,
            subject_name: subjectName,
            category: searchTask.category || "",
            query: searchTask.query || "",
            title: "",
            link: "",
            snippet: "",
            source: "",
            queue_rank: searchTask.queue_rank || null,
            priority_band: searchTask.priority_band || "",
            extraction_confidence: "no_results"
          },
          processing_status: "finding_normalized"
        }
      }
    ];

const items = $input.all();

if (!items.length) {
  return [
    {
      json: {
        case_id: "",
        primary_subject_name: "",
        subject_type: "",
        full_name: "",
        company_name: "",
        date_of_birth: "",
        nationality: "",
        country_of_residence: "",
        aliases: [],
        geography_scope: {},
        workflow_control: {},
        normalized_findings: [],
        normalized_findings_count: 0,
        processing_status: "findings_aggregated"
      }
    }
  ];
}

const first = items[0].json;

const findings = items
  .map(item => item.json.normalized_finding)
  .filter(Boolean);

return [
  {
    json: {
      case_id: first.case_id || "",
      subject_type: first.subject_type || "",
      primary_subject_name: first.primary_subject_name || "",
      full_name: first.full_name || "",
      company_name: first.company_name || "",
      date_of_birth: first.date_of_birth || "",
      nationality: first.nationality || "",
      country_of_residence: first.country_of_residence || "",
      aliases: first.aliases || [],
      geography_scope: first.geography_scope || {},
      workflow_control: first.workflow_control || {},
      ai_search_plan: first.ai_search_plan || {},
      normalized_findings: findings,
      normalized_findings_count: findings.length,
      processing_status: "findings_aggregated"
    }
  }
];

const aiItem = $input.item.json;
const sourceItem = $("SEARCH | Aggregate Findings For Analysis").item.json || {};

let raw =
  aiItem.output ||
  aiItem.text ||
  aiItem.response ||
  aiItem.result ||
  aiItem.message ||
  "";

if (typeof raw === "string") {
  raw = raw.trim();

  if (raw.startsWith("```json")) {
    raw = raw.replace(/^```json\s*/i, "").replace(/\s*```$/, "");
  } else if (raw.startsWith("```")) {
    raw = raw.replace(/^```\s*/i, "").replace(/\s*```$/, "");
  }
}

let parsedReport = null;
let parseError = null;

try {
  parsedReport = typeof raw === "string" ? JSON.parse(raw) : raw;
} catch (err) {
  parseError = err.message;
}

return [
  {
    json: {
      case_id: sourceItem.case_id || "",
      subject_type: sourceItem.subject_type || "",
      primary_subject_name: sourceItem.primary_subject_name || "",
      full_name: sourceItem.full_name || "",
      company_name: sourceItem.company_name || "",
      date_of_birth: sourceItem.date_of_birth || "",
      nationality: sourceItem.nationality || "",
      country_of_residence: sourceItem.country_of_residence || "",
      aliases: sourceItem.aliases || [],
      geography_scope: sourceItem.geography_scope || {},
      workflow_control: {
        ...(sourceItem.workflow_control || {}),
        llm_provider: "google_gemini"
      },
      ai_search_plan: sourceItem.ai_search_plan || {},
      normalized_findings: sourceItem.normalized_findings || [],
      normalized_findings_count: sourceItem.normalized_findings_count || 0,
      osint_report_raw: raw,
      osint_report_draft: parsedReport,
      osint_report_parse_error: parseError,
      processing_status: parsedReport ? "report_draft_ready" : "report_draft_parse_failed"
    }
  }
];

const item = $input.item.json;
const report = item.osint_report_draft || {};

return [
  {
    json: {
      ...item,
      word_report_mapping: {
        case_metadata: {
          case_id: item.case_id || "",
          report_type: item.workflow_control?.report_type || "osint_review_report",
          generated_at: new Date().toISOString(),
          llm_provider: item.workflow_control?.llm_provider || "google_gemini",
          final_decision_by_human: item.workflow_control?.final_decision_by_human ?? true
        },
        executive_summary: report.executive_summary || "",
        target_profile: {
          name: report.target_profile?.name || item.primary_subject_name || "",
          subject_type: report.target_profile?.subject_type || item.subject_type || "",
          dob: report.target_profile?.dob || item.date_of_birth || "",
          nationality: report.target_profile?.nationality || item.nationality || "",
          residence: report.target_profile?.residence || item.country_of_residence || "",
          aliases: report.target_profile?.aliases || item.aliases || []
        },
        search_scope_methodology: report.search_scope_methodology || "",
        identity_resolution: {
          status: report.identity_resolution?.status || "",
          analysis: report.identity_resolution?.analysis || ""
        },
        pep_public_office_results: {
          status: report.pep_public_office_results?.status || "",
          analysis: report.pep_public_office_results?.analysis || ""
        },
        sanctions_watchlist_results: {
          status: report.sanctions_watchlist_results?.status || "",
          analysis: report.sanctions_watchlist_results?.analysis || ""
        },
        offshore_financial_integrity_results: {
          status: report.offshore_financial_integrity_results?.status || "",
          analysis: report.offshore_financial_integrity_results?.analysis || ""
        },
        adverse_media_results: {
          status: report.adverse_media_results?.status || "",
          analysis: report.adverse_media_results?.analysis || ""
        },
        corporate_links_ownership_results: {
          status: report.corporate_links_ownership_results?.status || "",
          analysis: report.corporate_links_ownership_results?.analysis || ""
        },
        risk_assessment: {
          overall_risk: report.risk_assessment?.overall_risk || "",
          rationale: report.risk_assessment?.rationale || ""
        },
        recommended_next_steps: report.recommended_next_steps || [],
        analyst_review_notes: report.analyst_review_notes || [],
        appendix: {
          normalized_findings_count: item.normalized_findings_count || 0,
          normalized_findings: item.normalized_findings || []
        }
      },
      processing_status: "word_mapping_ready"
    }
  }
];

assignments.value:
={{
  {
